import '../../../../../core/protocol/navivox_event.dart';
import '../shared/text/transcript_display_text.dart';

enum TranscriptSafetyNoticeTone { warning, approval }

class TranscriptSafetyNoticePresentation {
  const TranscriptSafetyNoticePresentation({
    required this.tone,
    required this.cardKeyValue,
    required this.title,
    required this.message,
    required this.severityLabel,
    required this.risk,
  });

  factory TranscriptSafetyNoticePresentation.fromNotice(
    NavivoxSafetyNotice notice, {
    required bool approval,
  }) {
    return TranscriptSafetyNoticePresentation(
      tone: approval
          ? TranscriptSafetyNoticeTone.approval
          : TranscriptSafetyNoticeTone.warning,
      cardKeyValue: approval ? 'approval-required-card' : 'safety-warning-card',
      title: approval ? 'Approval required' : 'Safety warning',
      message: notice.message,
      severityLabel: notice.severity,
      risk: notice.risk,
    );
  }

  final TranscriptSafetyNoticeTone tone;
  final String cardKeyValue;
  final String title;
  final String message;
  final String? severityLabel;
  final String? risk;

  bool get showSeverity =>
      tone == TranscriptSafetyNoticeTone.warning &&
      transcriptHasDisplayText(severityLabel);

  bool get showRisk => transcriptHasDisplayText(risk);
}

import '../../../../../core/protocol/navivox_event.dart';
import '../shared/text/transcript_display_text.dart';

class TranscriptTextMessagePresentation {
  const TranscriptTextMessagePresentation({required this.text});

  factory TranscriptTextMessagePresentation.fromMessage(
    NavivoxChatMessage message,
  ) {
    return TranscriptTextMessagePresentation(text: message.text ?? '');
  }

  final String text;

  bool get hasText => transcriptHasDisplayText(text);
}

import '../../../../../core/protocol/navivox_event.dart';
import '../shared/text/transcript_display_text.dart';

enum TranscriptToolCallStatusTone { active, success, failure, neutral }

class TranscriptToolArtifactPresentation {
  const TranscriptToolArtifactPresentation({
    required this.id,
    required this.kind,
    required this.title,
    required this.summary,
    required this.ref,
  });

  factory TranscriptToolArtifactPresentation.fromArtifact(
    NavivoxToolArtifact artifact,
  ) {
    return TranscriptToolArtifactPresentation(
      id: artifact.id,
      kind: artifact.kind,
      title: artifact.title,
      summary: artifact.summary,
      ref: artifact.ref,
    );
  }

  final String id;
  final String kind;
  final String title;
  final String? summary;
  final String? ref;

  bool get showSummary => transcriptHasDisplayText(summary);
  bool get showRef => transcriptHasDisplayText(ref);
}

class TranscriptToolCallPresentation {
  const TranscriptToolCallPresentation({
    required this.name,
    required this.statusLabel,
    required this.statusTone,
    required this.summary,
    required this.approvalLabel,
    required this.approvalPrompt,
    required this.approvalRisk,
    required this.artifacts,
  });

  factory TranscriptToolCallPresentation.fromToolCall(
    NavivoxToolCall toolCall,
  ) {
    return TranscriptToolCallPresentation(
      name: toolCall.name,
      statusLabel: toolCall.status,
      statusTone: statusToneFor(toolCall.status),
      summary: toolCall.summary,
      approvalLabel: toolCall.approval == null ? null : 'Approval required',
      approvalPrompt: toolCall.approval?.prompt,
      approvalRisk: toolCall.approval?.risk,
      artifacts: [
        for (final artifact in toolCall.artifacts)
          TranscriptToolArtifactPresentation.fromArtifact(artifact),
      ],
    );
  }

  final String name;
  final String statusLabel;
  final TranscriptToolCallStatusTone statusTone;
  final String summary;
  final String? approvalLabel;
  final String? approvalPrompt;
  final String? approvalRisk;
  final List<TranscriptToolArtifactPresentation> artifacts;

  bool get showSummary => transcriptHasDisplayText(summary);
  bool get showApproval => transcriptHasDisplayText(approvalLabel);

  static TranscriptToolCallStatusTone statusToneFor(String status) {
    return switch (status) {
      'started' || 'updated' => TranscriptToolCallStatusTone.active,
      'finished' || 'completed' => TranscriptToolCallStatusTone.success,
      'failed' => TranscriptToolCallStatusTone.failure,
      _ => TranscriptToolCallStatusTone.neutral,
    };
  }
}

import '../../../../../core/protocol/navivox_event.dart';
import '../shared/text/transcript_display_text.dart';

class TranscriptVoiceMessagePresentation {
  const TranscriptVoiceMessagePresentation({
    required this.title,
    required this.durationLabel,
    required this.transcript,
    required this.morphIntensity,
  });

  factory TranscriptVoiceMessagePresentation.fromVoice(
    NavivoxVoiceMessage voice,
  ) {
    return TranscriptVoiceMessagePresentation(
      title: 'Voice message',
      durationLabel: '${voice.duration.inSeconds}s',
      transcript: voice.transcript,
      morphIntensity: voice.confidence,
    );
  }

  final String title;
  final String durationLabel;
  final String transcript;
  final double morphIntensity;

  bool get showTranscript => transcriptHasDisplayText(transcript);
}

